import json, sys, copy

PG_REAL = {"id": "kF6UjQ8hguq0ltLd", "name": "Postgres - n8n-whatsapp"}
PG_PLACEHOLDER_MARKERS = ["PG_CREDENTIAL_ID"]
HTTPHEADER_PLACEHOLDER_MARKERS = ["MONDAY_CREDENTIAL_ID", "META_CREDENTIAL_ID", "SMK_CREDENTIAL_ID"]

def transform_node(n):
    node = {
        "id": n["id"],
        "name": n["name"],
        "type": n["type"],
        "typeVersion": n["typeVersion"],
        "parameters": n.get("parameters", {}),
        "position": n.get("position", [0, 0]),
    }
    if "disabled" in n:
        node["disabled"] = n["disabled"]
    if "notes" in n:
        node["notes"] = n["notes"]

    creds = n.get("credentials")
    if creds:
        new_creds = {}
        for key, val in creds.items():
            if key == "postgres":
                cred_id = val.get("id", "")
                if cred_id in PG_PLACEHOLDER_MARKERS or "PG_CRED" in cred_id:
                    new_creds["postgres"] = dict(PG_REAL)
                else:
                    new_creds["postgres"] = val
            elif key == "httpHeaderAuth":
                cred_id = val.get("id", "")
                if any(m in cred_id for m in HTTPHEADER_PLACEHOLDER_MARKERS):
                    # omit entirely
                    continue
                else:
                    new_creds["httpHeaderAuth"] = val
            else:
                new_creds[key] = val
        if new_creds:
            node["credentials"] = new_creds
    return node

def chunk(lst, n):
    for i in range(0, len(lst), n):
        yield lst[i:i+n]

def main():
    infile = sys.argv[1]
    outprefix = sys.argv[2]
    max_ops = int(sys.argv[3]) if len(sys.argv) > 3 else 90

    with open(infile, encoding="utf-8") as f:
        wf = json.load(f)

    nodes = wf["nodes"]
    connections = wf.get("connections", {})

    add_node_ops = []
    for n in nodes:
        add_node_ops.append({"type": "addNode", "node": transform_node(n)})

    add_conn_ops = []
    for source_name, conn_obj in connections.items():
        main_arr = conn_obj.get("main", [])
        for source_index, targets in enumerate(main_arr):
            if not targets:
                continue
            for t in targets:
                add_conn_ops.append({
                    "type": "addConnection",
                    "source": source_name,
                    "sourceIndex": source_index,
                    "target": t["node"],
                    "targetIndex": t.get("index", 0),
                    "connectionType": t.get("type", "main"),
                })

    node_chunks = list(chunk(add_node_ops, max_ops))
    conn_chunks = list(chunk(add_conn_ops, max_ops))

    for i, c in enumerate(node_chunks):
        with open(f"{outprefix}.nodes.{i}.json", "w", encoding="utf-8") as f:
            json.dump(c, f, ensure_ascii=False, indent=1)
    for i, c in enumerate(conn_chunks):
        with open(f"{outprefix}.conns.{i}.json", "w", encoding="utf-8") as f:
            json.dump(c, f, ensure_ascii=False, indent=1)

    print(f"name={wf.get('name')}")
    print(f"total_nodes={len(nodes)}")
    print(f"total_node_ops={len(add_node_ops)} in {len(node_chunks)} chunks")
    print(f"total_conn_ops={len(add_conn_ops)} in {len(conn_chunks)} chunks")
    print(f"connection_keys={len(connections)}")

if __name__ == "__main__":
    main()

