const crypto    = require('crypto');
const payload   = JSON.stringify($json.body);
const signature = $json.headers['x-hub-signature-256'];
const secret    = $env.WA_APP_SECRET;

if (!secret) throw new Error('WA_APP_SECRET no configurado en el entorno de n8n');

const expected = 'sha256=' + crypto
  .createHmac('sha256', secret)
  .update(payload)
  .digest('hex');

if (!signature || signature !== expected) {
  throw new Error('X-Hub-Signature-256 inválida — request rechazado');
}

return $input.all();

const entry   = $json.body?.entry?.[0];
const change  = entry?.changes?.[0]?.value;

// Verificar si es un status (delivery) vs mensaje
if (change?.statuses) {
  return [{ json: { _tipo_evento: 'status', ...change.statuses[0] } }];
}

const msg  = change?.messages?.[0];
if (!msg) return [{ json: { _tipo_evento: 'otro' } }];

const tipo = msg.type;
let text_content     = '';
let flow_response    = null;
let flow_token       = '';
let is_flow_response = false;

if (tipo === 'interactive') {
  const ia = msg.interactive;
  if (ia?.type === 'button_reply') {
    text_content = ia.button_reply.id;
  } else if (ia?.type === 'nfm_reply') {
    flow_response    = JSON.parse(ia.nfm_reply.response_json);
    flow_token       = flow_response.flow_token ?? '';
    text_content     = 'nfm_reply';
    is_flow_response = true;
  }
} else if (tipo === 'text') {
  text_content = msg.text?.body?.toLowerCase().trim() || '';
}

return [{
  json: {
    _tipo_evento:    'mensaje',
    waid:            msg.from,
    db_phone:        msg.from,
    text_content,
    flow_response,
    flow_token,
    is_flow_response
  }
}];

const flow_token = $('Code: Normalizar mensaje').item.json.flow_token;
console.error(`flow_token no encontrado: ${flow_token}`);
return [{ json: { status: 'error', reason: 'flow_token_not_found', flow_token } }];

// Tomar datos del lookup y de los mapas
const envio     = $('PG: Lookup por wa_flow_token').item.json;
const preguntas = $('PG: Mapa preguntas y pesos').all().map(i => i.json);
const opciones  = $('PG: Mapa opciones').all().map(i => i.json);
const flowResponse = $('Code: Normalizar mensaje').item.json.flow_response;

if (!preguntas.length) {
  throw new Error(`Sin preguntas en maestro para encuesta: ${envio.codigo_encuesta} v${envio.version_num}`);
}

const filas = preguntas.map(pregunta => {
  const valor_raw    = flowResponse[pregunta.id_externo_pregunta];
  const esComentario = pregunta.codigo_metrica === 'COMENTARIO';

  let valor_numerico        = null;
  let valor_calculado       = null;
  let respuesta_comentario  = null;

  if (esComentario) {
    respuesta_comentario = valor_raw ?? null;
  } else {
    const opcion = opciones.find(
      o => o.codigo_pregunta === pregunta.codigo_pregunta && o.id_externo_opcion === valor_raw
    );
    valor_numerico  = opcion?.valor_numerico != null ? parseFloat(opcion.valor_numerico) : null;
    const peso      = parseFloat(pregunta.peso_final_calculado || 0);
    valor_calculado = (valor_numerico !== null && peso > 0)
      ? parseFloat((valor_numerico * peso).toFixed(4))
      : null;
  }

  return {
    json: {
      id_campana:           envio.id_campana,
      id_envio:             envio.id,
      codigo_encuesta:      envio.codigo_encuesta,
      version_num:          envio.version_num,
      codigo_pregunta:      pregunta.codigo_pregunta,
      id_grupo_respuesta:   envio.wa_flow_token,
      codigo_isi:           envio.codigo_isi,
      razon_social:         envio.razon_social,
      codigo_metrica:       pregunta.codigo_metrica,
      peso_final_calculado: parseFloat(pregunta.peso_final_calculado || 0),
      valor_numerico,
      valor_calculado,
      respuesta_comentario,
      atributos_adicionales: JSON.stringify({
        id_externo_pregunta: pregunta.id_externo_pregunta,
        raw_value: valor_raw
      }),
      // para mutations monday
      id_externo_collector: envio.id_externo_collector
    }
  };
});

return filas;

