import { workflow, trigger } from '@n8n/workflow-sdk';

const placeholderTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Placeholder Start', position: [0, 0] },
  output: [{}]
});

export default workflow('wf-smk-ingest-respuestas', 'WF-SMK-INGEST-RESPUESTAS')
  .add(placeholderTrigger);

parameters.jsCode:
// Recupera el timestamp de la última ejecución exitosa.
// Primera vez: procesa las últimas 25h para no perder nada.
const sd = $getWorkflowStaticData('global');
const fallback = new Date(Date.now() - 25 * 60 * 60 * 1000)
  .toISOString().replace('T', ' ').substring(0, 19);
const lastPoll = sd.smk_last_poll || fallback;
const nowIso  = new Date().toISOString().replace('T', ' ').substring(0, 19);
return [{ json: { last_poll: lastPoll, run_started_at: nowIso } }];

// Extrae el array de responses del bulk endpoint.
// Propaga smk_survey_id e id_encuesta_maestro a cada item.
const bulk      = $input.first().json;
const responses = bulk.data || [];
const surveyCtx = $('Loop: Por survey').first().json;

if (responses.length === 0) {
  return [{ json: { has_responses: false, smk_survey_id: surveyCtx.smk_survey_id } }];
}

return responses.map(r => ({
  json: {
    has_responses:     true,
    smk_response_id:   r.id,
    smk_survey_id:     surveyCtx.smk_survey_id,
    id_encuesta_ctx:   surveyCtx.id_encuesta,
    smk_collector_id:  r.collector_id,
    date_modified:     r.date_modified
  }
}));

// Extrae y limpia todos los datos relevantes de la response.
// Filtra preguntas sin respuesta (pages con questions: []).
// Determina 'origen' a partir de collection_mode (campo disponible en details).
const r    = $input.first().json;
const cv   = r.custom_variables || {};
const loop = $('Loop: Por response').first().json;

// Determinar origen desde collection_mode
const collectionModeMap = {
  default:  'WEBLINK',
  email:    'EMAIL',
  offline:  'FISICO',
  ios:      'APP',
  android:  'APP'
};
const origen = collectionModeMap[r.collection_mode] || 'WEBLINK';

// Filtrar páginas con preguntas respondidas (quita páginas vacías y preguntas sin answers)
const pagesConRespuestas = (r.pages || []).map(page => ({
  ...page,
  questions: (page.questions || []).filter(q => q.answers && q.answers.length > 0)
})).filter(page => page.questions.length > 0);

return [{
  json: {
    smk_response_id:  r.id,
    smk_survey_id:    r.survey_id,
    smk_collector_id: r.collector_id,
    id_encuesta_ctx:  loop.id_encuesta_ctx,
    response_status:  r.response_status,
    collection_mode:  r.collection_mode,
    origen,
    date_created:     r.date_created,
    // Identidad del respondente (vacío si link no personalizado)
    codigo_isi:       cv.cod   || null,
    nombre_empresa:   cv.dis   || null,
    email:            cv.email || null,
    // Páginas con respuestas
    pages: pagesConRespuestas
  }
}];

