parameters.jsCode:
const ctx       = $('Set: Consolidar contexto').first().json;
const idEnvio   = $('PG: Upsert envio').first().json.id_envio;
const preguntas = $('PG: Mapa preguntas').all().map(i => i.json);
const opciones  = $('PG: Mapa opciones').all().map(i => i.json);
const pages     = ctx.pages || [];

// Maps de lookup rápido
const preguntasMap = new Map(preguntas.map(p => [p.id_externo_pregunta, p]));
const opcionesMap  = new Map(opciones.map(o => [o.id_externo_opcion, o]));

const filas = [];

for (const page of pages) {
  for (const pregSmk of (page.questions || [])) {
    const preg = preguntasMap.get(pregSmk.id);
    if (!preg) continue; // Pregunta no registrada en diccionario (ej: imagen)

    const esComentario = preg.id_metrica === 'COMENTARIO';
    let valor_numerico       = null;
    let valor_calculado      = null;
    let respuesta_comentario = null;
    let smk_choice_id        = null;

    if (esComentario) {
      // Pregunta de texto libre
      respuesta_comentario = pregSmk.answers?.[0]?.text || null;
    } else {
      const answer = pregSmk.answers?.[0];
      if (answer) {
        smk_choice_id = answer.choice_id;

        // Fuente primaria: weight directo en la respuesta (más rápido)
        const w = answer.choice_metadata?.weight;
        valor_numerico = w !== undefined ? parseFloat(w) : null;

        // Fallback: lookup en opciones_maestro por choice_id
        if (valor_numerico === null) {
          const opc = opcionesMap.get(smk_choice_id);
          valor_numerico = opc ? parseFloat(opc.valor_numerico) : null;
        }

        const peso = parseFloat(preg.peso_final_calculado);
        valor_calculado = (valor_numerico !== null && peso > 0)
          ? parseFloat((valor_numerico * peso).toFixed(6))
          : null;
      }
    }

    filas.push({
      json: {
        id_ejecucion:          ctx.id_ejecucion,
        id_envio:              idEnvio,
        id_encuesta_maestro:   ctx.id_encuesta_maestro,
        version_num:           ctx.version_num,
        id_pregunta_maestro:   preg.id_pregunta,
        id_grupo_respuesta:    idEnvio,
        codigo_isi:            ctx.codigo_isi,
        nombre_empresa:        ctx.nombre_empresa,
        canal:                 'SURVEYMONKEY',
        origen:                ctx.origen,
        id_metrica:            preg.id_metrica,
        peso_final_calculado:  preg.peso_final_calculado,
        valor_numerico,
        valor_calculado,
        respuesta_comentario,
        atributos_adicionales: JSON.stringify({
          smk_response_id:  ctx.smk_response_id,
          smk_question_id:  pregSmk.id,
          smk_choice_id,
          smk_collector_id: ctx.smk_collector_id
        })
      }
    });
  }
}

// Si no hay filas (respuesta solo con comentarios vacíos), devolver señal
return filas.length > 0
  ? filas
  : [{ json: { _sin_filas: true } }];

// Persiste el timestamp de esta ejecución para el próximo polling.
const sd = $getWorkflowStaticData('global');
sd.smk_last_poll = $('Code: Init timestamp').first().json.run_started_at;
return [{ json: { updated_last_poll: sd.smk_last_poll } }];

